      assert Jason.decode!(response.body) == %{"detail" => "1 validation error in request", "errors" => [%{"ctx" => %{"pattern" => "^[A-Z]{3}[0-9]{4}$"}, "input" => "ABC-123", "loc" => ["body", "sku"], "msg" => "String should match pattern '^[A-Z]{3}[0-9]{4}$'", "type" => "string_pattern_mismatch"}], "status" => 422, "title" => "Request Validation Failed", "type" => "https://spikard.dev/errors/validation-error"}
    end
  end

  describe "string_pattern_validation_success" do
    test "POST /items/validated - Tests string field with regex pattern constraint success" do
      {:ok, response} = Req.post(client(), url: "/items/validated", json: %{"name" => "Item", "sku" => "ABC1234"}, headers: [{"Content-Type", "application/json"}])
      assert response.status == 200
      assert Jason.decode!(response.body) == %{"name" => "Item", "sku" => "ABC1234"}
    end
  end

  describe "uuid_field_invalid_format" do
    test "POST /items/ - Tests UUID field with invalid UUID format" do
      {:ok, response} = Req.post(client(), url: "/items/", json: %{"item_id" => "not-a-valid-uuid", "name" => "Item"}, headers: [{"Content-Type", "application/json"}])
      assert response.status == 422
      assert Jason.decode!(response.body) == %{"detail" => "1 validation error in request", "errors" => [%{"input" => "not-a-valid-uuid", "loc" => ["body", "item_id"], "msg" => "Input should be a valid UUID", "type" => "uuid_parsing"}], "status" => 422, "title" => "Request Validation Failed", "type" => "https://spikard.dev/errors/validation-error"}
    end
  end

  describe "uuid_field_success" do
    test "POST /items/ - Tests UUID field with valid UUID format" do
      {:ok, response} = Req.post(client(), url: "/items/", json: %{"item_id" => "c892496f-b1fd-4b91-bdb8-b46f92df1716", "name" => "Item"}, headers: [{"Content-Type", "application/json"}])
      assert response.status == 200
      assert Jason.decode!(response.body) == %{"item_id" => "c892496f-b1fd-4b91-bdb8-b46f92df1716", "name" => "Item"}
    end
  end
end
